import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length before copying to buffer
        if (name.length() > 10) {
            System.out.println("Input too long. Please enter a name with at most 10 characters.");
            return;
        }

        // Copy input to buffer safely
        char[] buffer = new char[10];
        name.getChars(0, Math.min(name.length(), buffer.length), buffer, 0);

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
